           :key="image.name"
      >
            <span>
              {{ image.name }}
            </span>
      </div>
    </el-card>

    <el-dialog
        :footer="null"
        :maskClosable="false"
        width="30%"
        style="text-align: center"
        v-model="openLinkDialog">
      <p v-if="currentClickItem.message">{{ currentClickItem.message }}</p>
      <li style="margin-bottom: 10px" v-for="address in currentClickItem.addressList" :key="address.label">
        <a :href=address.address target="_blank">{{ address.label }}</a>
      </li>
    </el-dialog>
  </div>
</template>

<script setup>
import {ref} from "vue";
import {useImageStore} from "@/store/image";

const openLinkDialog = ref(false)
const currentClickItem = ref()

