import {defineStore} from 'pinia'
import {ref} from "vue";

export const useImageStore
    = defineStore('image', () => {
        const image = ref([
            {
                name: '星穹铁道壁纸',
                addressList: [
                    {
                        label: '流萤  7zon',
                        address: 'https://baixia.lanzoul.com/b01lyvymj'
                    }
                ]
            }
        ])

        return {
            image
        }
    },
    {
        persist: false
    }
)

