import {defineStore} from 'pinia'
import {ref} from "vue";

export const useMallStore
    = defineStore('mall', () => {
        const mall = ref([
            {
                label: '最优软件',
                address: 'https://filehippo.com/zh/'
            },
            {
                label: 'SourceForge',
                address: 'https://sourceforge.net/'
            },
            {
                label: '清华大学开源软件镜像站',
                address: 'https://mirrors.tuna.tsinghua.edu.cn/'
            },
            {
                label: 'MavenLibs',
                address: 'https://mavenlibs.com/'
            },
            {
                label: 'MSDN',
                address: 'https://msdn.itellyou.cn/'
            },
        ])

        return {
            mall
        }
    },
    {
        persist: false
    }
)

