import {defineStore} from 'pinia'
import {ref} from "vue";

export const useBookStore
    = defineStore('book', () => {
        const book = ref([
            {
                label: '红楼梦',
                address: './files/红楼梦.txt'
            }
        ])

        return {
            book
        }
    },
    {
        persist: false
    }
)

